# Worked focus: http-py-language-charset-negotiation — Interpret charset and language metadata, negotiation quality values, and Unicode boundaries without locale guesses. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_fields_representations_4(content_type: str, accepted_types: set[str], body_bytes: int) -> dict[str, object]:
    assert isinstance(content_type, str) and isinstance(body_bytes, int)
    media_type = content_type.partition(";")[0].strip().casefold()
    accepted = 0 <= body_bytes <= 1_048_576 and media_type in accepted_types
    return {"media_type": media_type, "accepted": accepted}

